import{_ as t,c as a,o as s,ae as i}from"./chunks/framework.CDjunVez.js";const p=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"features/security.md","filePath":"features/security.md"}'),r={name:"features/security.md"};function o(n,e,l,c,h,d){return s(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><h2 id="full-system-audit-health-report" tabindex="-1">Full System Audit &amp; Health Report <a class="header-anchor" href="#full-system-audit-health-report" aria-label="Permalink to &quot;Full System Audit &amp; Health Report&quot;">​</a></h2><p>The <code>kiwipanel check</code> command is one of the <strong>core safety features</strong> of KiwiPanel.<br> It performs a deep, structured inspection of the server and reports the current <strong>health, security posture, and runtime readiness</strong> of the system.</p><p>This command is intentionally <strong>transparent, read-only by default, and automation-friendly</strong>.</p><hr><h2 id="why-kiwipanel-check-exists" tabindex="-1">Why <code>kiwipanel check</code> Exists <a class="header-anchor" href="#why-kiwipanel-check-exists" aria-label="Permalink to &quot;Why `kiwipanel check` Exists&quot;">​</a></h2><p>Modern servers fail quietly:</p><ul><li>A firewall is installed but inactive</li><li>SSH is exposed with weak settings</li><li>Disks fill up without warning</li><li>Services stop after reboot</li><li>Permissions drift over time</li></ul><p><code>kiwipanel check</code> exists to <strong>surface these problems early</strong>, using <strong>real system state</strong>, not assumptions.</p><blockquote><p>If something is wrong, you should see it immediately.</p></blockquote><p>FYI, the command is basically forked from the <a href="https://github.com/vernu/vps-audit" target="_blank" rel="noreferrer">Vernu vps-audit</a>. We also <strong>added some additional checks</strong> to ensure the system is ready for production.</p><hr><h2 id="basic-usage" tabindex="-1">Basic Usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic Usage&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kiwipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span></span></code></pre></div>',14)])])}const m=t(r,[["render",o]]);export{p as __pageData,m as default};
